import React, { useState } from 'react';
import './calc.css';

function Calc() {
  const [monitorText, setMonitorText] = useState('');

  const handleClick = (value) => {
    setMonitorText((prevText) => prevText + value);
  };

  const handleInputChange = (event) => {
    setMonitorText(event.target.value);
  };

  return (
    <div className='wrap'>
      <div className='calc'>
        <input 
          type='text' 
          className='monitor' 
          value={monitorText} 
          onChange={handleInputChange} 
    
        />
        <div className='calc-button'>
          <button onClick={() => handleClick('9')}>9</button>
          <button onClick={() => handleClick('8')}>8</button>
          <button onClick={() => handleClick('7')}>7</button>
          <button onClick={() => handleClick('+')}>➕</button>
          <button onClick={() => handleClick('6')}>6</button>
          <button onClick={() => handleClick('5')}>5</button>
          <button onClick={() => handleClick('4')}>4</button>
          <button onClick={() => handleClick('-')}>➖</button>
          <button onClick={() => handleClick('3')}>3</button>
          <button onClick={() => handleClick('2')}>2</button>
          <button onClick={() => handleClick('1')}>1</button>
          <button onClick={() => handleClick('*')}>✖️</button>
          <button className='btn-zero' onClick={() => handleClick('0')}>0</button>
          <button onClick={() => handleClick('.')}>.</button>
          <button onClick={() => handleClick('/')}>➗</button>
          <button onClick={() => setMonitorText(monitorText.slice(0, -1))}>🔙</button>
          <button onClick={() => setMonitorText('')}>DEL</button>
          <button className='btn-result' onClick={() => setMonitorText(eval(monitorText))}>🟰</button>
        </div>
      </div>
    </div>
  );
}

export default Calc;
